int main() {
    gpio_init(LED_PIN);
    gpio_set_dir(LED_PIN, true);

    const uint32_t bit = (1u &lt;&lt; LED_PIN);
    while (true) {
        gpio_xor_mask(bit); // alternar SOLO ese pin
        sleep_ms(500);
    }
}
